# -*- coding: utf-8 -*-
import numpy as np
import subprocess
import time
import re
import json
import logging
import os
from collections import deque
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple, Any
from datetime import datetime

# Safe psutil import with fallback
try:
    import psutil as _ps
except ImportError:
    _ps = None

logger = logging.getLogger(__name__)

@dataclass
class ContextScore:
    """Result of context scoring analysis"""
    final_score: float
    signals: Dict[str, float]
    target_met: bool
    recommended_actions: List[str] = field(default_factory=list)
    penalty_breakdown: Dict[str, float] = field(default_factory=dict)
    metadata: Dict[str, Any] = field(default_factory=dict)
    complexity_types: List[Any] = field(default_factory=list)
    resource_requirement: Any = None
    recommended_percentage: int = 0
    estimated_time_multiplier: float = 0.0
    reasoning: str = ""
    factors: Dict[str, float] = field(default_factory=dict)


@dataclass
class ScoringSignal:
    """Individual scoring signal from consideration matrix"""
    name: str
    value: float
    weight: float
    penalty: float
    description: str

class AdaptiveContextScorer:
    """
    Context scoring system optimized for consumer hardware constraints.
    Implements C3R-L methodology with dynamic resource adaptation.
    """

    def __init__(self, config_manager):
        self.config = config_manager
        self.memory_threshold = 0.85  # 85% RAM usage triggers optimization
        self.history = deque(maxlen=1000)  # Context history buffer
        self.model_cache = {}  # Lightweight model response cache

        # Hardware-aware thresholds with safe detection
        # Expose hardware snapshot attributes used by other modules
        self.system_memory = self._get_system_memory_gb()   # float, GB
        self.gpu_memory = self._get_gpu_memory_gb()         # float, GB

        # Dynamic scoring weights based on hardware capability
        self.weights = self._calculate_hardware_weights()

        # Initialize pattern sets with safe defaults
        # JSON structure detection (very permissive, avoids crashes)
        self.json_patterns = {
            'valid_structure': r"\{[\s\S]*\}|\[[\s\S]*\]"
        }

        # Duplicate detection patterns (disabled by default to avoid false positives)
        # Can be populated via configuration in the future
        self.duplicate_patterns: List[str] = []

    # --- hardware probes (fast, safe) -------------------------------------
    def _get_system_memory_gb(self) -> float:
        """Get system memory in GB with safe fallbacks"""
        try:
            if _ps:
                return float(_ps.virtual_memory().total) / (1024**3)
            # /proc/meminfo fallback
            with open("/proc/meminfo", "r", encoding="utf-8") as f:
                content = f.read()
                match = re.search(r"MemTotal:\s+(\d+)\s+kB", content)
                if match:
                    return float(match.group(1)) / (1024**2)  # kB to GB
        except Exception:
            pass
        return 16.0  # Conservative default

    def _get_gpu_memory_gb(self) -> float:
        """Get GPU memory in GB with multiple detection methods"""
        # Prefer quant_manager's detector if available
        try:
            from .quant_manager import DynamicQuantizationManager
            qm = DynamicQuantizationManager()
            if hasattr(qm, 'gpu_memory') and qm.gpu_memory > 0:
                return float(qm.gpu_memory)
        except Exception:
            pass

        # Fallback: nvidia-smi (MB to GB)
        try:
            output = subprocess.check_output(
                ["nvidia-smi", "--query-gpu=memory.total", "--format=csv,noheader,nounits"],
                text=True, timeout=3, stderr=subprocess.DEVNULL
            )
            values = [float(x.strip()) / 1024.0 for x in output.splitlines() if x.strip()]
            return max(values) if values else 0.0
        except Exception:
            pass

        # Final fallback: estimation based on system memory
        return self._estimate_gpu_from_system_memory()

    def _estimate_gpu_from_system_memory(self) -> float:
        """Fallback GPU memory estimation"""
        memory_map = {
            8: 8.0,   # RTX 3060, 4060
            12: 12.0, # RTX 3060 12GB, 4070
            16: 16.0, # RTX 4060Ti 16GB
            24: 24.0, # RTX 3090, 4090
            32: 24.0  # High-end systems
        }
        sys_mem = int(self.system_memory)
        return memory_map.get(sys_mem, 12.0)  # Conservative 12GB default

    def hardware_snapshot(self) -> dict:
        """Convenience hardware snapshot for other modules"""
        return {
            "system_memory_gb": self.system_memory,
            "gpu_memory_gb": self.gpu_memory
        }


    def _calculate_hardware_weights(self) -> Dict[str, float]:
        """Calculate scoring weights based on available hardware"""
        base_weights = {"complexity": 0.3, "relevance": 0.35, "urgency": 0.2, "resource_cost": 0.15}

        # Adjust for constrained hardware
        if self.gpu_memory < 16:
            base_weights["resource_cost"] = 0.25  # Emphasize resource efficiency
            base_weights["complexity"] = 0.25  # Reduce complexity tolerance

        if self.system_memory < 16:
            base_weights["resource_cost"] = 0.3  # Further emphasize efficiency

        return base_weights

    def score_context_quality(self, context: str, intent_type: str, user_input: str = "") -> ContextScore:
        """
        Main scoring method implementing consideration matrix logic
        Reference: Context Scoring System.txt "Score = 100 − (weighted penalties)"
        """

        # Get appropriate signal weights for this intent type
        performance_targets = getattr(self.config.routing, 'performance_targets', {})
        if hasattr(performance_targets, 'get'):
            weights = performance_targets.get(intent_type, performance_targets.get('general', {}))
        else:
            weights = {}

        # Ensure weights is a dict
        if not isinstance(weights, dict):
            weights = {}

        # Calculate individual signals
        signals = {}
        penalties = {}

        # Lane appropriateness signal
        lane_score, lane_penalty = self._score_lane_appropriateness(context, intent_type, user_input)
        signals['lane_appropriateness'] = lane_score
        penalties['lane_appropriateness'] = lane_penalty * weights.get('lane_appropriateness', 0.2)

        # Context-specific signals
        if intent_type == 'structured':
            format_score, format_penalty = self._score_format_consistency(context, user_input)
            duplicate_score, duplicate_penalty = self._score_duplicates(context)
            json_score, json_penalty = self._score_json_validity(context)
            constraint_score, constraint_penalty = self._score_constraint_adherence(context, user_input)

            signals.update({
                'format_consistency': format_score,
                'duplicate_penalty': duplicate_score,
                'json_validity': json_score,
                'constraint_adherence': constraint_score
            })

            # Use safe default weights when not configured
            penalties.update({
                'format_consistency': format_penalty * float(weights.get('format_consistency', 0.25)),
                'duplicate_penalty': duplicate_penalty * float(weights.get('duplicate_penalty', 0.15)),
                'json_validity': json_penalty * float(weights.get('json_validity', 0.20)),
                'constraint_adherence': constraint_penalty * float(weights.get('constraint_adherence', 0.20))
            })

        elif intent_type == 'recall':
            memory_score, memory_penalty = self._score_memory_accuracy(context)
            relevance_score, relevance_penalty = self._score_context_relevance(context, user_input)
            factual_score, factual_penalty = self._score_factual_consistency(context)
            brevity_score, brevity_penalty = self._score_brevity(context)

            signals.update({
                'memory_accuracy': memory_score,
                'context_relevance': relevance_score,
                'factual_consistency': factual_score,
                'brevity_score': brevity_score
            })

            penalties.update({
                'memory_accuracy': memory_penalty * float(weights.get('memory_accuracy', 0.30)),
                'context_relevance': relevance_penalty * float(weights.get('context_relevance', 0.30)),
                'factual_consistency': factual_penalty * float(weights.get('factual_consistency', 0.20)),
                'brevity_score': brevity_penalty * float(weights.get('brevity_score', 0.20))
            })

        elif intent_type == 'reasoning':
            flow_score, flow_penalty = self._score_logical_flow(context)
            evidence_score, evidence_penalty = self._score_evidence_quality(context)
            structure_score, structure_penalty = self._score_argument_structure(context)
            depth_score, depth_penalty = self._score_depth_analysis(context)

            signals.update({
                'logical_flow': flow_score,
                'evidence_quality': evidence_score,
                'argument_structure': structure_score,
                'depth_analysis': depth_score
            })

            penalties.update({
                'logical_flow': flow_penalty * float(weights.get('logical_flow', 0.25)),
                'evidence_quality': evidence_penalty * float(weights.get('evidence_quality', 0.25)),
                'argument_structure': structure_penalty * float(weights.get('argument_structure', 0.25)),
                'depth_analysis': depth_penalty * float(weights.get('depth_analysis', 0.25))
            })

        else:  # general case
            quality_score, quality_penalty = self._score_response_quality(context)
            relevance_score, relevance_penalty = self._score_context_relevance(context, user_input)
            coherence_score, coherence_penalty = self._score_coherence(context)
            constraint_score, constraint_penalty = self._score_constraint_adherence(context, user_input)

            signals.update({
                'response_quality': quality_score,
                'context_relevance': relevance_score,
                'coherence': coherence_score,
                'constraint_adherence': constraint_score
            })

            penalties.update({
                'response_quality': quality_penalty * weights.get('response_quality', 0.25),
                'context_relevance': relevance_penalty * weights.get('context_relevance', 0.25),
                'coherence': coherence_penalty * weights.get('coherence', 0.15),
                'constraint_adherence': constraint_penalty * weights.get('constraint_adherence', 0.15)
            })

        # Calculate final score: Score = 100 − (weighted penalties)
        total_penalty = sum(penalties.values())
        final_score = max(0, 100 - total_penalty)

        # Check if target is met (defensive against non-dict configs)
        routing_cfg = getattr(self.config, 'routing', None)
        perf_targets = getattr(routing_cfg, 'performance_targets', {}) if routing_cfg else {}
        if not hasattr(perf_targets, 'get'):
            perf_targets = {}
        target = perf_targets.get(intent_type, perf_targets.get('general', 80.0))
        target_met = final_score >= target

        # Generate recommended actions
        recommended_actions = self._generate_repair_actions(signals, penalties, intent_type)

        return ContextScore(
            final_score=final_score,
            signals=signals,
            target_met=target_met,
            recommended_actions=recommended_actions,
            penalty_breakdown=penalties,
            metadata={
                'intent_type': intent_type,
                'target_score': target,
                'context_length': len(context),
                'analysis_timestamp': datetime.now().isoformat()
            }
        )

    def _score_lane_appropriateness(self, context: str, intent_type: str, user_input: str) -> Tuple[float, float]:
        """Score whether context is appropriate for the intended lane"""
        score = 1.0
        penalty = 0.0

        # Check for lane mismatch indicators
        if intent_type == 'structured':
            # Structured tasks should have clear formatting hints
            if not any(pattern in user_input.lower() for pattern in ['list', 'json', 'format', 'table', 'items']):
                score -= 0.3
                penalty += 15

            # Should have concise, focused content
            if len(context.split()) > 1000:
                score -= 0.2
                penalty += 10

        elif intent_type == 'recall':
            # Recall tasks should reference previous content
            if not any(pattern in user_input.lower() for pattern in ['how many', 'what did', 'remind', 'recall']):
                score -= 0.4
                penalty += 20

            # Should have minimal new reasoning
            reasoning_words = ['because', 'therefore', 'analysis', 'conclude']
            if sum(1 for word in reasoning_words if word in context.lower()) > 3:
                score -= 0.2
                penalty += 10

        elif intent_type == 'reasoning':
            # Reasoning tasks should have analytical content
            if not any(pattern in user_input.lower() for pattern in ['why', 'how', 'explain', 'analyze']):
                score -= 0.3
                penalty += 15

            # Should allow for longer responses
            if len(context.split()) < 50:
                score -= 0.2
                penalty += 10

        return max(0, score), penalty

    def _score_format_consistency(self, context: str, user_input: str) -> Tuple[float, float]:
        """Score format consistency for structured tasks"""
        score = 1.0
        penalty = 0.0

        # Check for JSON format requests
        if 'json' in user_input.lower():
            if not re.search(self.json_patterns['valid_structure'], context.strip()):
                score -= 0.5
                penalty += 25

        # Check for list format requests
        if any(word in user_input.lower() for word in ['list', 'items', 'examples']):
            # Should have numbered or bulleted items
            list_patterns = [r'^\d+\.', r'^[•\-*]', r'^\w+:\s*']
            lines = context.split('\n')
            list_lines = sum(1 for line in lines if any(re.match(pattern, line.strip()) for pattern in list_patterns))

            if list_lines == 0 and len(lines) > 2:
                score -= 0.4
                penalty += 20

        # Check for table format requests
        if 'table' in user_input.lower():
            if '|' not in context and '\t' not in context:
                score -= 0.3
                penalty += 15

        return max(0, score), penalty

    def _score_duplicates(self, context: str) -> Tuple[float, float]:
        """Detect and penalize duplicate content"""
        score = 1.0
        penalty = 0.0

        for pattern in self.duplicate_patterns:
            matches = re.findall(pattern, context, re.IGNORECASE | re.MULTILINE)
            if matches:
                duplicate_count = len(matches)
                score -= min(0.4, duplicate_count * 0.1)
                penalty += min(20, duplicate_count * 5)

        return max(0, score), penalty

    def _score_json_validity(self, context: str) -> Tuple[float, float]:
        """Score JSON validity when JSON is expected"""
        score = 1.0
        penalty = 0.0

        try:
            # Try to parse as JSON
            json.loads(context.strip())
            score = 1.0  # Perfect JSON
        except json.JSONDecodeError:
            # Check for partial JSON structures
            if re.search(self.json_patterns['valid_structure'], context):
                score = 0.7  # Looks like JSON but invalid
                penalty = 15
            else:
                score = 0.5  # No JSON structure
                penalty = 25

        return score, penalty

    def _score_constraint_adherence(self, context: str, user_input: str) -> Tuple[float, float]:
        """Score adherence to explicit constraints"""
        score = 1.0
        penalty = 0.0

        # Extract number constraints
        number_matches = re.findall(r'(\d+)\s*(?:items?|examples?|points?)', user_input.lower())
        if number_matches:
            requested_count = int(number_matches[0])

            # Count actual items in response
            lines = [line.strip() for line in context.split('\n') if line.strip()]
            item_patterns = [r'^\d+\.', r'^[•\-*]', r'^\w+:\s*']
            actual_count = sum(1 for line in lines if any(re.match(pattern, line) for pattern in item_patterns))

            if actual_count == 0:
                actual_count = len(lines)  # Fallback to line count

            # Penalize deviation from requested count
            deviation = abs(actual_count - requested_count) / max(requested_count, 1)
            if deviation > 0.2:  # More than 20% deviation
                score -= min(0.4, deviation)
                penalty += min(20, deviation * 50)

        return max(0, score), penalty

    def _score_memory_accuracy(self, context: str) -> Tuple[float, float]:
        """Score memory accuracy for recall tasks"""
        score = 1.0
        penalty = 0.0

        # Basic heuristics for memory accuracy
        # Check for uncertainty markers
        uncertainty_markers = ['maybe', 'might', 'probably', 'not sure', 'i think']
        uncertainty_count = sum(1 for marker in uncertainty_markers if marker in context.lower())

        if uncertainty_count > 2:
            score -= 0.3
            penalty += 15

        # Check for specificity (good for recall)
        specific_markers = ['exactly', 'precisely', 'specifically', 'the number was']
        specificity_count = sum(1 for marker in specific_markers if marker in context.lower())

        if specificity_count > 0:
            score += 0.1  # Bonus for specificity

        return max(0, min(1.0, score)), penalty

    def _score_context_relevance(self, context: str, user_input: str) -> Tuple[float, float]:
        """Score relevance of context to user input"""
        score = 1.0
        penalty = 0.0

        # Simple keyword overlap scoring
        user_words = set(user_input.lower().split())
        context_words = set(context.lower().split())

        # Remove common words
        common_words = {'the', 'a', 'an', 'and', 'or', 'but', 'in', 'on', 'at', 'to', 'for', 'of', 'with', 'by'}
        user_words -= common_words
        context_words -= common_words

        if user_words:
            overlap = len(user_words & context_words) / len(user_words)
            if overlap < 0.2:
                score -= 0.3
                penalty += 15
            elif overlap > 0.6:
                score += 0.1  # Bonus for high relevance

        return max(0, min(1.0, score)), penalty

    def _score_factual_consistency(self, context: str) -> Tuple[float, float]:
        """Score factual consistency (basic contradiction detection)"""
        score = 1.0
        penalty = 0.0

        # Basic contradiction detection
        sentences = context.split('.')
        contradiction_patterns = [
            (r'\bnot\b.*\bis\b', r'\bis\b.*\bnot\b'),
            (r'\bno\b.*\byes\b', r'\byes\b.*\bno\b'),
            (r'\btrue\b.*\bfalse\b', r'\bfalse\b.*\btrue\b')
        ]

        for pos_pattern, neg_pattern in contradiction_patterns:
            if any(re.search(pos_pattern, s, re.IGNORECASE) for s in sentences) and \
               any(re.search(neg_pattern, s, re.IGNORECASE) for s in sentences):
                score -= 0.4
                penalty += 20

        return max(0, score), penalty

    def _score_brevity(self, context: str) -> Tuple[float, float]:
        """Score brevity for recall tasks"""
        score = 1.0
        penalty = 0.0

        word_count = len(context.split())

        # Recall should be brief
        if word_count > 100:
            excess = (word_count - 100) / 100
            score -= min(0.5, excess * 0.3)
            penalty += min(25, excess * 15)

        return max(0, score), penalty

    def _score_logical_flow(self, context: str) -> Tuple[float, float]:
        """Score logical flow for reasoning tasks"""
        score = 1.0
        penalty = 0.0

        # Check for logical connectors
        logical_connectors = ['therefore', 'because', 'thus', 'consequently', 'as a result', 'furthermore']
        connector_count = sum(1 for connector in logical_connectors if connector in context.lower())

        sentences = context.split('.')
        if len(sentences) > 3 and connector_count == 0:
            score -= 0.3
            penalty += 15

        return max(0, score), penalty

    def _score_evidence_quality(self, context: str) -> Tuple[float, float]:
        """Score evidence quality for reasoning tasks"""
        score = 1.0
        penalty = 0.0

        # Check for evidence markers
        evidence_markers = ['data shows', 'research indicates', 'studies show', 'according to']
        evidence_count = sum(1 for marker in evidence_markers if marker in context.lower())

        # Reasoning tasks should have some evidence
        word_count = len(context.split())
        if word_count > 50 and evidence_count == 0:
            score -= 0.2
            penalty += 10

        return max(0, score), penalty

    def _score_argument_structure(self, context: str) -> Tuple[float, float]:
        """Score argument structure for reasoning tasks"""
        score = 1.0
        penalty = 0.0

        # Check for structured argument elements
        structure_markers = ['first', 'second', 'finally', 'in conclusion', 'to summarize']
        structure_count = sum(1 for marker in structure_markers if marker in context.lower())

        sentences = context.split('.')
        if len(sentences) > 5 and structure_count == 0:
            score -= 0.2
            penalty += 10

        return max(0, score), penalty

    def _score_depth_analysis(self, context: str) -> Tuple[float, float]:
        """Score depth of analysis for reasoning tasks"""
        score = 1.0
        penalty = 0.0

        # Check for analysis depth indicators
        depth_markers = ['implications', 'underlying', 'root cause', 'deeper analysis', 'furthermore']
        depth_count = sum(1 for marker in depth_markers if marker in context.lower())

        word_count = len(context.split())
        if word_count > 100 and depth_count == 0:
            score -= 0.3
            penalty += 15

        return max(0, score), penalty

    def _score_response_quality(self, context: str) -> Tuple[float, float]:
        """Score general response quality"""
        score = 1.0
        penalty = 0.0

        # Basic quality indicators
        if len(context.strip()) < 10:
            score -= 0.5
            penalty += 25

        # Check for complete thoughts
        if not context.strip().endswith(('.', '!', '?', '```')):
            score -= 0.2
            penalty += 10

        return max(0, score), penalty

    def _score_coherence(self, context: str) -> Tuple[float, float]:
        """Score coherence and readability"""
        score = 1.0
        penalty = 0.0

        # Check for repeated sentence starters
        sentences = [s.strip() for s in context.split('.') if s.strip()]
        if len(sentences) > 2:
            starters = [s.split()[0].lower() if s.split() else '' for s in sentences]
            unique_starters = len(set(starters))
            if unique_starters < len(starters) * 0.7:
                score -= 0.2
                penalty += 10

        return max(0, score), penalty

    def _generate_repair_actions(self, signals: Dict[str, float], penalties: Dict[str, float], intent_type: str) -> List[str]:
        """Generate recommended repair actions based on scoring results"""
        actions = []

        # Find the worst performing signals
        worst_signals = sorted(penalties.items(), key=lambda x: x[1], reverse=True)[:3]

        for signal_name, penalty in worst_signals:
            if penalty > 10:  # Only suggest actions for significant penalties
                if signal_name == 'lane_appropriateness':
                    actions.append(f"Consider routing to different lane - current route may not match intent type '{intent_type}'")
                elif signal_name == 'format_consistency':
                    actions.append("Improve format consistency - ensure response matches requested format (JSON, list, table)")
                elif signal_name == 'duplicate_penalty':
                    actions.append("Remove duplicate content - detected repeated text in response")
                elif signal_name == 'json_validity':
                    actions.append("Fix JSON structure - response should be valid JSON when JSON format requested")
                elif signal_name == 'constraint_adherence':
                    actions.append("Follow explicit constraints - match requested item counts and specifications")
                elif signal_name == 'memory_accuracy':
                    actions.append("Improve memory accuracy - reduce uncertainty markers, increase specificity")
                elif signal_name == 'context_relevance':
                    actions.append("Increase context relevance - ensure response directly addresses user query")
                elif signal_name == 'brevity_score':
                    actions.append("Increase brevity - recall responses should be concise and to the point")
                elif signal_name == 'logical_flow':
                    actions.append("Improve logical flow - add logical connectors and clear reasoning structure")
                elif signal_name == 'evidence_quality':
                    actions.append("Strengthen evidence - include data, research, or concrete examples")

        return actions


class DynamicContextPruner:
    """
    Dynamic Context Pruning implementing EdgeInfinite-style selective preservation
    Reference: Context Scoring Systempt2.txt "80% of context can be pruned with minimal degradation"
    """

    def __init__(self):
        self.importance_patterns = {
            'high_importance': [
                r'^\d+\.',  # Numbered lists
                r'^[•\-*]',  # Bullet points
                r':\s*$',  # Definitions/labels
                r'\b(?:error|warning|important|note|todo)\b',  # Keywords
                r'```.*```',  # Code blocks
                r'\b\d+\s*(?:items?|examples?|points?)\b'  # Count references
            ],
            'medium_importance': [
                r'\b(?:therefore|because|thus|however|moreover)\b',  # Logical connectors
                r'\b(?:first|second|finally|in conclusion)\b',  # Structure markers
                r'\?|!',  # Questions and exclamations
                r'\b(?:user|assistant):\s*',  # Dialog markers
            ],
            'low_importance': [
                r'\b(?:the|a|an|and|or|but|in|on|at|to|for|of|with|by)\b',  # Common words
                r'\s+',  # Whitespace
                r'\. {2,}',  # Multiple periods
            ]
        }

    def prune_context_intelligently(self, context: str, target_tokens: int = 2000, intent_type: str = 'general') -> str:
        """
        Apply intelligent context pruning with selective preservation
        Reference: Context Scoring Systempt2.txt EdgeInfinite architecture
        """

        # Tokenize context (simple word-based approximation)
        words = context.split()
        current_tokens = len(words)

        if current_tokens <= target_tokens:
            return context

        # Calculate tokens to remove
        tokens_to_remove = current_tokens - target_tokens
        removal_ratio = tokens_to_remove / current_tokens

        logger.info(f"Pruning context: {current_tokens} -> {target_tokens} tokens ({removal_ratio:.1%} reduction)")

        # Apply EdgeInfinite-style selective preservation
        # Reference: "300 sink tokens + 200 window tokens"
        sink_tokens = min(300, current_tokens // 4)  # Always preserve start
        window_tokens = min(200, current_tokens // 5)  # Always preserve recent

        # Extract preserved sections
        sink_content = ' '.join(words[:sink_tokens])
        window_content = ' '.join(words[-window_tokens:])

        # Process middle section with importance scoring
        middle_words = words[sink_tokens:-window_tokens] if len(words) > sink_tokens + window_tokens else []

        if middle_words:
            scored_words = self._score_word_importance(middle_words, intent_type)

            # Calculate how many middle tokens we can keep
            budget_remaining = target_tokens - sink_tokens - window_tokens
            budget_remaining = max(0, budget_remaining)

            # Sort by importance and take top words within budget
            scored_words.sort(key=lambda x: x[1], reverse=True)
            preserved_middle = [word for word, score in scored_words[:budget_remaining]]

            # Reconstruct middle content maintaining some order
            middle_content = self._reconstruct_ordered_content(middle_words, preserved_middle)
        else:
            middle_content = ""

        # Combine sections with pruning indicators
        pruned_context = self._combine_pruned_sections(
            sink_content, middle_content, window_content, removal_ratio
        )

        logger.info(f"Context pruning complete: {len(context.split())} -> {len(pruned_context.split())} words")

        return pruned_context

    def _score_word_importance(self, words: List[str], intent_type: str) -> List[Tuple[str, float]]:
        """Score individual words for importance"""
        scored_words = []

        for word in words:
            importance_score = 0.5  # Base score

            # Apply pattern-based scoring
            word_lower = word.lower()

            # High importance patterns
            for pattern in self.importance_patterns['high_importance']:
                if re.search(pattern, word, re.IGNORECASE):
                    importance_score += 0.4
                    break

            # Medium importance patterns
            for pattern in self.importance_patterns['medium_importance']:
                if re.search(pattern, word, re.IGNORECASE):
                    importance_score += 0.2
                    break

            # Low importance patterns (penalty)
            for pattern in self.importance_patterns['low_importance']:
                if re.search(pattern, word, re.IGNORECASE):
                    importance_score -= 0.1
                    break

            # Intent-specific adjustments
            if intent_type == 'structured':
                if re.match(r'^\d+\.', word) or word in ['•', '-', '*']:
                    importance_score += 0.3
            elif intent_type == 'recall':
                if word_lower in ['how', 'many', 'what', 'when', 'where', 'who']:
                    importance_score += 0.3
            elif intent_type == 'reasoning':
                if word_lower in ['because', 'therefore', 'thus', 'analysis', 'conclude']:
                    importance_score += 0.3

            # Length penalty for very long words (likely less important)
            if len(word) > 15:
                importance_score -= 0.1

            scored_words.append((word, max(0, importance_score)))

        return scored_words

    def _reconstruct_ordered_content(self, original_words: List[str], preserved_words: List[str]) -> str:
        """Reconstruct content maintaining relative order of preserved words"""
        preserved_set = set(preserved_words)

        # Maintain order from original, only including preserved words
        ordered_preserved = [word for word in original_words if word in preserved_set]

        return ' '.join(ordered_preserved)

    def _combine_pruned_sections(self, sink: str, middle: str, window: str, removal_ratio: float) -> str:
        """Combine pruned sections with appropriate indicators"""
        sections = []

        if sink:
            sections.append(sink)

        if middle:
            if removal_ratio > 0.5:
                # High pruning - add indicator
                sections.append(f"...[context pruned: {removal_ratio:.0%} removed]...")
                sections.append(middle)
            else:
                # Moderate pruning - minimal indicator
                sections.append("...")
                sections.append(middle)

        if window:
            if middle:  # Add separator if we have middle content
                sections.append("...")
            sections.append(window)

        return ' '.join(sections)

    def calculate_pruning_efficiency(self, original_context: str, pruned_context: str, score_before: float, score_after: float) -> Dict[str, float]:
        """Calculate efficiency metrics for pruning operation"""
        original_tokens = len(original_context.split())
        pruned_tokens = len(pruned_context.split())

        compression_ratio = 1 - (pruned_tokens / original_tokens) if original_tokens > 0 else 0
        score_preservation = score_after / score_before if score_before > 0 else 1.0

        # Efficiency = compression achieved vs. quality preserved
        efficiency = compression_ratio * score_preservation

        return {
            'compression_ratio': compression_ratio,
            'score_preservation': score_preservation,
            'efficiency': efficiency,
            'tokens_removed': original_tokens - pruned_tokens,
            'original_tokens': original_tokens,
            'pruned_tokens': pruned_tokens
        }


# -*- coding: utf-8 -*-

if __name__ == "__main__":  # dev-only: runs only when executed as a script
    import os, re as _re
    _quiet = os.environ.get("OPENCODE_REGEX_CHECK_QUIET", "1") != "0"
    _patterns_to_check = [
        r'^\d+\.',          # numbered list
        r'^[•\-*]',         # bullets (• - *)
        r'^\w+:\s*',        # label: value
        r'\bnot\b.*\bis\b', r'\bis\b.*\bnot\b',
        r'\bno\b.*\byes\b', r'\byes\b.*\bno\b',
        r'\btrue\b.*\bfalse\b', r'\bfalse\b.*\btrue\b',
    ]
    _errors = 0
    for _p in _patterns_to_check:
        try:
            _re.compile(_p)
            if not _quiet:
                print(f"Regex OK: {_p}")
        except _re.error as e:
            _errors += 1
            print(f"Regex ERROR: {_p} - {e}")
    if _errors:
        raise SystemExit(f"{_errors} regex pattern(s) failed to compile")
